/* Standard Bootstrap color variables */
:root {
  --gray-base: #000;
  --gray-darker: #222;
  --brand-primary: #2C8EDD;
  --brand-success: #5cb85c;
  --brand-info: #5bc0de;
  --brand-warning: #f0ad4e;
  --brand-danger: #d9534f;
